      <div className="w-full max-sm:max-w-xs max-w-sm bg-white rounded-[2rem] overflow-hidden shadow-2xl animate-in zoom-in-95 duration-300">
        <div className="relative bg-gradient-to-br from-purple-600 via-pink-500 to-orange-500 p-8 pb-10 text-white">
          <button 
            onClick={() => navigate('/dashboard', { state: { name, email } })}
