// --- Types for Wallet Management ---
interface Transaction {
  id: string;
  type: 'Credit' | 'Debit';
  label: string;
  amount: number;
  date: string;
}

interface UserWallet {
  balance: number;
  transactions: Transaction[];
}

// --- Helper for Local Storage Wallet ---
const getWallet = (email: string): UserWallet => {
  const data = localStorage.getItem(`paygo_wallet_${email}`);
  if (data) return JSON.parse(data);
  const initial: UserWallet = {
    balance: 180000,
    transactions: [
      {
        id: 'init-1',
        type: 'Credit',
        label: 'Welcome Bonus',
        amount: 180000,
        date: new Date().toLocaleDateString()
      }
    ]
  };
  localStorage.setItem(`paygo_wallet_${email}`, JSON.stringify(initial));
  return initial;
};

const updateWallet = (email: string, wallet: UserWallet) => {
  localStorage.setItem(`paygo_wallet_${email}`, JSON.stringify(wallet));
};

const RegisterPage: React.FC = () => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    country: '',
    password: ''
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const navigate = useNavigate();

  const handleRegister = (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    setTimeout(() => {
      try {
        const existingUsers = JSON.parse(localStorage.getItem('paygo_users') || '[]');
        const userExists = existingUsers.some((u: any) => u.email.toLowerCase() === formData.email.toLowerCase());

        if (userExists) {
          setError('An account with this email already exists on this device.');
          setLoading(false);
          return;
        }

        const newUser = { ...formData };
        existingUsers.push(newUser);
        localStorage.setItem('paygo_users', JSON.stringify(existingUsers));

        // Initialize wallet for new user
        getWallet(formData.email);

        setLoading(false);
        navigate('/welcome', { state: { name: formData.name, email: formData.email } });
      } catch (err) {
        setError('Something went wrong. Please try again.');
        setLoading(false);
      }
    }, 1500);
  };

  return (
    <div className="w-full animate-in fade-in duration-500">
      <h1 className="text-3xl font-bold text-[#1a1b3a] mb-8 text-center">
        Register to continue
      </h1>

      {error && (
        <div className="mb-4 p-4 bg-red-50 border border-red-100 text-red-600 rounded-2xl text-sm font-medium animate-shake">
          {error}
        </div>
      )}

      <form onSubmit={handleRegister} className="w-full space-y-4">
        <Input 
          placeholder="Enter Name" 
          value={formData.name}
          onChange={(e) => setFormData({...formData, name: e.target.value})}
          required
        />
        <Input 
          type="email" 
          placeholder="Enter Email" 
          value={formData.email}
          onChange={(e) => setFormData({...formData, email: e.target.value})}
          required
        />
        <Select 
          options={COUNTRIES} 
          value={formData.country}
          onChange={(e) => setFormData({...formData, country: e.target.value})}
          required
        />
        <Input 
          type="password" 
          placeholder="Enter Password" 
          value={formData.password}
          onChange={(e) => setFormData({...formData, password: e.target.value})}
          required
        />

        <button 
          type="submit"
          disabled={loading}
          className="w-full h-16 bg-black text-white rounded-2xl text-xl font-medium mt-8 hover:bg-gray-900 transition-colors shadow-lg active:scale-[0.98] disabled:opacity-70 flex items-center justify-center"
        >
          {loading ? (
            <i className="fas fa-circle-notch animate-spin"></i>
          ) : (
            'Register'
          )}
        </button>
      </form>

      <div className="mt-12 text-center">
        <Link to="/login" className="text-purple-600 font-medium hover:text-purple-700 transition-colors">
          Already have an account? Login
        </Link>
      </div>
    </div>
  );
};

