const LoginPage: React.FC = () => {
  const [formData, setFormData] = useState({
    email: '',
    password: ''
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const navigate = useNavigate();

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    setTimeout(() => {
      try {
        const existingUsers = JSON.parse(localStorage.getItem('paygo_users') || '[]');
        const matchedUser = existingUsers.find(
          (u: any) => u.email.toLowerCase() === formData.email.toLowerCase() && u.password === formData.password
        );

        if (matchedUser) {
          setLoading(false);
          navigate('/dashboard', { state: { name: matchedUser.name, email: matchedUser.email } });
        } else {
          setError('Account not found on this device or invalid credentials. You must register on this device first.');
          setLoading(false);
        }
      } catch (err) {
        setError('Something went wrong. Please try again.');
        setLoading(false);
      }
    }, 1500);
  };

  return (
    <div className="w-full animate-in fade-in duration-500">
      <h1 className="text-3xl font-bold text-[#1a1b3a] mb-8 text-center">
        Login to PayGo
      </h1>

      {error && (
        <div className="mb-4 p-4 bg-red-50 border border-red-100 text-red-600 rounded-2xl text-sm font-medium animate-shake">
          {error}
        </div>
      )}

      <form onSubmit={handleLogin} className="w-full space-y-4">
        <Input 
          type="email" 
          placeholder="Enter Email" 
          value={formData.email}
          onChange={(e) => setFormData({...formData, email: e.target.value})}
          required
        />
        <Input 
          type="password" 
          placeholder="Enter Password" 
          value={formData.password}
          onChange={(e) => setFormData({...formData, password: e.target.value})}
          required
        />

        <button 
          type="submit"
          disabled={loading}
          className="w-full h-16 bg-black text-white rounded-2xl text-xl font-medium mt-8 hover:bg-gray-900 transition-colors shadow-lg active:scale-[0.98] disabled:opacity-70 flex items-center justify-center"
        >
          {loading ? (
            <i className="fas fa-circle-notch animate-spin"></i>
          ) : (
            'Login'
          )}
        </button>
      </form>

      <div className="mt-12 text-center">
        <Link to="/" className="text-purple-600 font-medium hover:text-purple-700 transition-colors">
          Don't have an account? Register
        </Link>
      </div>
    </div>
  );
};

const App: React.FC = () => {
  return (
    <Router>
      <Layout>
        <Routes>
          <Route path="/" element={<RegisterPage />} />
          <Route path="/welcome" element={<WelcomePage />} />
          <Route path="/onboarding" element={<OnboardingWizard />} />
          <Route path="/dashboard" element={<DashboardPage />} />
          <Route path="/buy-pay-id" element={<BuyPayIdPage />} />
          <Route path="/transfer" element={<TransferPage />} />
          <Route path="/upgrade" element={<UpgradeAccountPage />} />
          <Route path="/login" element={<LoginPage />} />
        </Routes>
      </Layout>
    </Router>
  );
};

export default App;
